const { exec } = require('child_process');

function resizeImage(inputFilename, outputFilename, dimensions, effects) {
  const commandParts = [
    'gm', // Use GraphicsMagick for advanced features
    'convert',
    inputFilename,
    '-resize', dimensions,
  ];

  effects.forEach(effect => {
    switch (effect.toLowerCase()) {
      case 'grayscale':
        commandParts.push('-colorspace', 'gray');
        break;
      case 'sepia':
        commandParts.push('-modulate', '100,50,50');
        break;
      case 'blur':
        commandParts.push('-blur', '2x2');
        break;
      case 'enhance':
        commandParts.push('-enhance');
        break;
      default:
        console.warn(`Unknown effect: ${effect}`);
    }
  });

  commandParts.push(outputFilename);

  exec(commandParts.join(' '), (error, stdout, stderr) => {
    if (error) {
      console.error(`Error resizing image: ${stderr}`);
      return;
    }
    console.log(`Image resized successfully to ${outputFilename}`);
  });
}

// Example usage:
resizeImage('user_photo.jpg', 'thumb.jpg', '200x200', ['grayscale', 'enhance']);